mapper.select:
select b.id id, b.project_name name, b.train_type trainType, b.train_way train_way, IFNULL(train_sdate, IFNULL(practice_sdate, exam_sdate)) startDate, IFNULL(train_edate, IFNULL(practice_edate, exam_edate)) endDate, IFNULL(a.is_sign, 1) status, ((SELECT COUNT(DISTINCT courseware_id) FROM xm_project_person_study_record z WHERE z.project_id = b.id AND status = 2 AND z.person_id = a.person_id AND z.is_delete = 0) / (SELECT COUNT(1) FROM xm_project_relate x LEFT JOIN xm_course_relation_courseware y ON x.relate_ids = y.course_id LEFT JOIN xm_courseware z ON y.courseware_id = z.id WHERE x.project_id = b.id AND x.is_delete = 0 AND y.is_delete = 0 AND z.is_delete = 0 AND z.type IN (1, 2) AND x.type = 2)) * 100 schedule, a.learn_hours learnHours, (SELECT score FROM xm_answer_report WHERE project_id = b.id AND person_id = #{studentId} AND is_delete = 0 AND type = 2 AND course_id IS NULL ORDER BY create_time DESC LIMIT 1) score FROM xm_project b LEFT JOIN xm_person_course_relate a ON a.project_id = b.id WHERE b.is_delete = 0 AND a.person_id = #{studentId} AND a.is_delete = 0 AND b.project_status > 2 AND (b.project_type = 1 OR a.id IS NOT NULL) -- 查询系统项目与自主项目
AND b.project_name like concat('%',#{name},'%')
-- 1-必修 2-选修 AND b.train_type = #{trainType}
AND b.project_type = #{projectType}
-- 查询状态 AND a.is_sign = #{status}
AND a.create_time >= #{startDate}
ORDER BY schedule DESC, a.create_time DESC

select sum(study_hours) from xm_project a
left join xm_project_person_study_record b on b.project_id = a.id
where b.is_delete = 0 and a.is_delete = 0 and year(b.create_time) = #{year}

    and a.train_type = #{trainType}

and person_id = #{personId}
